INSERT INTO love_quotes (quote, author) VALUES ('遇见你，是我这辈子最美丽的意外。','佚名'),('你是我遇见的所有美好里的刚刚好。','佚名'),('世界很大，但我的心很小，小到只能装下你一个人。','佚名'),('余生漫漫，爱你不止三千遍。','佚名'),('和你在一起的日子，每一天都值得被珍藏。','佚名'),('喜欢是乍见之欢，爱是久处不厌。','佚名'),('我不想做你的路人，我只想做你的心上人。','佚名'),('所谓幸福，就是有一个愿意听你讲废话的人。','佚名'),('我的世界原本是一片荒芜，直到你来。','佚名'),('最好的爱情，是两个人一起变成更好的人。','佚名'),('有你的地方，就是家。','佚名'),('你是我平淡生活里的光。','佚名'),('一见钟情是你，日久生情也是你。','佚名'),('你若安好，便是晴天。','佚名'),('爱不是彼此凝视，而是一起朝同一个方向看。','圣埃克苏佩里'),('陪伴是最长情的告白。','佚名'),('在所有人声鼎沸的欢喜里，我唯独望向你。','佚名'),('我目光短浅，眼里只有你。','佚名'),('你若不离不弃，我必生死相依。','佚名'),('爱你，是我做过的最好的事。','佚名'),('人间烟火，山河远阔，无一是你，无一不是你。','佚名'),('我想和你一起慢慢变老。','佚名'),('你的笑容，是我每天最想看到的风景。','佚名'),('三生有幸遇见你，纵使悲凉也是情。','佚名'),('春风十里不如你。','冯唐'),('这世间虽有千般好，但唯有你最珍贵。','佚名'),('愿得一人心，白首不相离。','卓文君'),('山有木兮木有枝，心悦君兮君不知。','佚名'),('执子之手，与子偕老。','《诗经》'),('你是我始料不及的遇见，也是我突如其来的欢喜。','佚名'),('在这善变的世界，我想和你看一看永远。','佚名'),('一生至少该有一次，为了某个人而忘了自己。','佚名'),('我想要的很简单，时光还在，你还在。','佚名'),('你是年少的欢喜，倒过来念也是。','佚名'),('和你在一起的时光，全都很耀眼。','佚名'),('世间万物论沧桑，你在心上作中央。','佚名'),('入目无别人，四下皆是你。','佚名'),('从此以后，你有我，我有你，我们有一个家。','佚名'),('往后余生，风雪是你，平淡是你，清贫也是你。','马良'),('世间美好与你环环相扣。','佚名'),('你是我的可遇不可求。','佚名'),('喜欢一个人，始于颜值，陷于才华，忠于人品。','佚名'),('乍见心欢，小别思恋，久处仍怦然。','佚名'),('我携星辰以赠你，仍觉星辰不如你。','佚名'),('你是我今生渡不过的劫，多看一眼就心软，拥抱一下就沦陷。','佚名'),('愿岁月可回首，且以深情共白头。','佚名'),('谢谢你，在这个世界的角落，找到了我。','佚名'),('一天一月一起一年一生。','佚名'),('因为有你，我变成了更好的自己。','佚名');
